import { cursor } from './cursor';
import { gamePaused } from './game';
import { grid } from './grid';
import { derived } from 'svelte/store';

export const keyboardDisabled = derived(
  [cursor, grid, gamePaused],
  ([$cursor, $grid, $gamePaused]) => {
    // 没有选中格子 或 游戏暂停 时禁用
    if (($cursor.x === null && $cursor.y === null) || $gamePaused) {
      return true;
    }
    
    // 如果是固定格（题目预设的数字），禁用
    const isGivenCell = grid.isGiven($cursor.x, $cursor.y);
    if (isGivenCell) {
      return true;
    }
    
    // 其他情况都允许（包括修改自己填过的数字）
    return false;
  }
);